import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from 'src/app/services/auth.service';
@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css'],
})
export class DashboardComponent {
  constructor(private router: Router, private authService: AuthService) {}

  goToTaskForm() {
    this.router.navigate(['/task-form']);
  }

  goToTaskList() {
    this.router.navigate(['/task-list']);
  }
  logout() {
    this.authService.logout().subscribe(
      () => {
        // Logout was successful
        // Clear any other local data or perform additional cleanup if needed
        this.router.navigate(['/login']); // Navigate to the login page
      },
      (error) => {
        // Handle logout error
        console.error('Logout failed', error);
      }
    );
  }
}
<div class="container mt-4 text-center">
  <h2 class="mb-3">Welcome to Task Management System</h2>
  <p class="lead">
    This is a simple Task Management System where you can organize and manage
    your tasks efficiently.
  </p>
  <p class="lead">You can add tasks here:</p>

  <div class="d-flex justify-content-center">
    <button class="btn btn-primary mx-2" (click)="goToTaskForm()">
      Add Task
    </button>
    <button class="btn btn-success mx-2" (click)="goToTaskList()">
      View Tasks
    </button>
  </div>

  <p class="lead mt-3">
    Click "Add Task" to add a new task using the Task Form, and click "View
    Tasks" to see your existing tasks in the Task List.
  </p>
  <button class="btn btn-danger mx-2" (click)="logout()">Logout</button>
</div>
